def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity < 0:
            priorities[i] = np.inf
            continue
        if capacity == 0:
            priorities[i] = 0 if item == 0 else np.inf
            continue
        ratio = item / capacity if capacity != 0 else np.inf
        if item == 0 and capacity > 0:
            priorities[i] = 0
            continue
        if ratio < 0:
            priorities[i] = np.inf
            continue
        score = 0.0
        factor = 1.0
        penalty = 0.0
        bonus = 0.0
        if ratio == 0:
            priorities[i] = 0
            continue
        if ratio > 3:
            for x in range(1, 7):
                for y in range(1, 5):
                    penalty += ((ratio ** (x + y)) / (x * y + 1)) * ((-1) ** (x + y))
            score = (ratio ** 5) / 5 + penalty
            priorities[i] = score * 2.5 if score > 0 else np.inf
        elif 2 < ratio <= 3:
            for q in range(1, 9):
                sign = (-1) ** (q+1)
                score += sign * (ratio ** q) / (q + 2)
            for r in range(1, 5):
                factor *= (1 - 1/(r + ratio + 2))
            priorities[i] = abs(score) * factor * 12
        elif 1 < ratio <= 2:
            for q in range(1, 8):
                sign = (-1) ** q
                score += sign * (ratio ** q) / (q + 1)
            for r in range(1, 4):
                factor *= (1 - 1/(r + ratio + 1))
            if ratio > 1.5:
                bonus += ratio * 2
                if ratio > 1.75:
                    penalty += ratio ** 3 / 7
                else:
                    penalty += ratio ** 2 / 5
            else:
                bonus += ratio ** 2 / 3
            priorities[i] = abs(score + bonus - penalty) * factor * 10
        elif 0 < ratio <= 1:
            temp_score = 0
            for p in range(1, 12):
                if p % 2 == 0:
                    temp_score += (ratio ** p) / (p * 1.5)
                else:
                    temp_score -= (ratio ** p) / (p * 2.5)
            multiplier = 25 if ratio < 0.2 else 18 if ratio < 0.4 else 12 if ratio < 0.6 else 8 if ratio < 0.8 else 4
            score = abs(temp_score) * multiplier
            if ratio > 0.85:
                extra = 0
                for m in range(1, 6):
                    extra += (ratio ** m) / (m + 1)
                if extra > 1:
                    factor = 1.2
                else:
                    factor = 0.9
                score += extra * 2 * factor
            threshold_count = 0
            for v in np.linspace(0.1, ratio, 5):
                if v > 0.5:
                    threshold_count += 1
            score *= (1 + threshold_count * 0.05)
            priorities[i] = score
        else:
            if item == 0:
                priorities[i] = 0
            else:
                priorities[i] = np.inf
    return priorities
